<?php
declare(strict_types=1);
return static function(PDO$pdo):void{
 $pdo->exec("CREATE TABLE IF NOT EXISTS notifications (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,user_id BIGINT UNSIGNED NOT NULL,notification_type VARCHAR(60) NOT NULL,title VARCHAR(180) NOT NULL,message VARCHAR(500) NOT NULL,priority VARCHAR(20) NOT NULL DEFAULT 'normal',related_type VARCHAR(60) NULL,related_id BIGINT UNSIGNED NULL,related_view VARCHAR(60) NULL,location_id BIGINT UNSIGNED NULL,deduplication_key CHAR(64) NOT NULL,read_at DATETIME NULL,created_at DATETIME NOT NULL,expires_at DATETIME NULL,CONSTRAINT fk_notification_user FOREIGN KEY(user_id) REFERENCES users(id),CONSTRAINT fk_notification_location FOREIGN KEY(location_id) REFERENCES locations(id),UNIQUE KEY uq_notification_dedup(user_id,deduplication_key),INDEX idx_notification_unread(user_id,read_at,created_at),INDEX idx_notification_expiry(expires_at)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");
 $p=$pdo->prepare("INSERT INTO permissions(code,module,action,name,created_at) VALUES(?,?,?,?,UTC_TIMESTAMP()) ON DUPLICATE KEY UPDATE name=VALUES(name)");foreach([['notifications.view','notifications','view','Consultar notificaciones propias'],['dashboards.view','dashboards','view','Consultar dashboard autorizado']]as$row)$p->execute($row);
 foreach(['superadmin','admin','supervisor','guard','resident']as$role){$s=$pdo->prepare("INSERT IGNORE INTO role_permissions(role_id,permission_id,created_at) SELECT r.id,p.id,UTC_TIMESTAMP() FROM roles r JOIN permissions p ON p.code IN ('notifications.view','dashboards.view') WHERE r.code=?");$s->execute([$role]);}
 $pdo->exec("INSERT INTO system_settings(setting_key,setting_value,value_type,is_public,created_at,updated_at) VALUES('notifications.retention_months','12','integer',0,UTC_TIMESTAMP(),UTC_TIMESTAMP()),('dashboards.refresh_seconds','60','integer',1,UTC_TIMESTAMP(),UTC_TIMESTAMP()) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value),updated_at=UTC_TIMESTAMP()");
};
